'''N-body integrator moduleThis module integrates N-body systems using two integrating methods:    - Runge-Kutta 4th Order (RK4): computes four intermediate derivatives at         each timestep and returns a single weighted state vector    - Leapfrog (Velocity Verlet, kick-drift-kick approach): updates velocity         at half-steps and returns full-step position and final half-step         velocity'''def rk4(s, t, dt, derivs, args=()):    '''    Evaluate a particle's state vector at time t + h using the Fourth-Order     Runge-Kutta method.        Parameters    ----------    s : ndarray, shape (6 * N,)        Interleaved state vector [x0, vx0, y0, vy0, z0, vz0, x1, vx1, ...].    t : float        Time    dt : float        Timestep    derivs : callable             Function that evaluates the right-hand side of the equations of              motion, returning the time derivatives of the state vector.        Returns    -------    s : ndarray, shape (6 * N,)        Updated interleaved state vector [x0, vx0, y0, vy0, z0, vz0, x1, vx1,                                          ...] at time t + dt.    '''    k1 = dt * derivs(s, t, *args)    k2 = dt * derivs(s + 0.5*k1, t + 0.5*dt, *args)    k3 = dt * derivs(s + 0.5*k2, t + 0.5*dt, *args)    k4 = dt * derivs(s + k3, t + dt, *args)    return s + (k1 + 2*k2 + 2*k3 + k4) / 6def leapfrog(s, t, dt, derivs, args=()):    '''    Evaluate a particle's state vector at time t + h using the Leapfrog method.        Parameters    ----------    s : ndarray, shape (6 * N,)        Interleaved state vector [x0, vx0, y0, vy0, z0, vz0, x1, vx1, ...].    t : float        Time    dt : float        Timestep    derivs : callable             Function that evaluates the right-hand side of the equations of              motion, returning the time derivatives of the state vector.        Returns    -------    s : ndarray, shape (6 * N,)        Updated interleaved state vector [x0, vx0, y0, vy0, z0, vz0, x1, vx1,                                          ...] at time t + dt.    '''        s[1::2] += 0.5 * dt * derivs(s, t, *args)[1::2]    s[0::2] += dt * s[1::2]    s[1::2] += 0.5 * dt * derivs(s, t + dt, *args)[1::2]    return s